private void xrTableCell75_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

    // Get RearFemBalance and RearFemMort values
    decimal rearFemBalance = Convert.ToDecimal(GetCurrentColumnValue("RearFemBalance") ?? 0);
    decimal rearFemMort = Convert.ToDecimal(GetCurrentColumnValue("RearFemMort") ?? 0);

    if (rearFemBalance != 0)
    {
        // Calculate rear female mortality percentage
        decimal result = (rearFemMort * 100) / rearFemBalance;
        cell.Text = result.ToString("N2") ;
    }
    else
    {
        cell.Text = "0.00";
    }
}

