private void xrTableCell77_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

    // Calculate TotalRearBalance (RearFemBalance + RearMaleBalance)
    decimal rearFemBalance = Convert.ToDecimal(GetCurrentColumnValue("RearFemBalance") ?? 0);
    decimal rearMaleBalance = Convert.ToDecimal(GetCurrentColumnValue("RearMaleBalance") ?? 0);
    decimal totalRearBalance = rearFemBalance + rearMaleBalance;

    // Calculate TotalRearingMort (RearFemMort + RearMaleMort)
    decimal rearFemMort = Convert.ToDecimal(GetCurrentColumnValue("RearFemMort") ?? 0);
    decimal rearMaleMort = Convert.ToDecimal(GetCurrentColumnValue("RearMaleMort") ?? 0);
    decimal totalRearingMort = rearFemMort + rearMaleMort;

    if (totalRearBalance != 0)
    {
        // Calculate total rearing mortality percentage
        decimal result = (totalRearingMort * 100) / totalRearBalance;
        cell.Text = result.ToString("N2");
    }
    else
    {
        cell.Text = "0.00";
    }
}

