private void xrTableCell118_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        XRTableCell cell = sender as XRTableCell;

    // Get LayStartMaleBalance
    decimal layStartMaleBalance = Convert.ToDecimal(GetCurrentColumnValue("LayStartMaleBalance") ?? 0);

    // Calculate TotalLayingMaleExcluded (LayMaleMort + LayMaleCulls + LayMaleSpiking)
    decimal layMaleMort = Convert.ToDecimal(GetCurrentColumnValue("LayMaleMort") ?? 0);
    decimal layMaleCulls = Convert.ToDecimal(GetCurrentColumnValue("LayMaleCulls") ?? 0);
    decimal layMaleSpiking = Convert.ToDecimal(GetCurrentColumnValue("LayMaleSpiking") ?? 0);
    decimal totalLayingMaleExcluded = layMaleMort + layMaleCulls + layMaleSpiking;

    if (layStartMaleBalance != 0)
    {
        // Calculate total laying male exclusion percentage
        decimal result = (totalLayingMaleExcluded * 100) / layStartMaleBalance;
        cell.Text = result.ToString("N2") ;
    }
    else
    {
        cell.Text = "0.00";
    }
}

private void xrTableCell99_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
            XRTableCell cell = sender as XRTableCell;

        decimal layingFemCullsPer = 0;
        decimal layingMaleMortPre = 0;
        decimal totalPercentage = 0;

            // Get values for calculations
        decimal layStartFemBalance = Convert.ToDecimal(GetCurrentColumnValue("LayStartFemBalance") ?? 0);
        decimal layFemCulls = Convert.ToDecimal(GetCurrentColumnValue("LayFemCulls") ?? 0);
        decimal layFemMort = Convert.ToDecimal(GetCurrentColumnValue("LayFemMort") ?? 0);

        // Calculate {@LayingFemCullsPer}
        if (layStartFemBalance != 0)
        {
            layingFemCullsPer = (layFemCulls * 100) / layStartFemBalance;
        }
        else
        {
            layingFemCullsPer = 0;
        }

        // Calculate {@LayingmaleMortPre}
        if (layStartFemBalance != 0)
        {
            layingMaleMortPre = (layFemMort * 100) / layStartFemBalance;
        }
        else
        {
            layingMaleMortPre = 0;
        }

        // Calculate total
        totalPercentage = layingFemCullsPer + layingMaleMortPre;
        cell.Text = totalPercentage.ToString("N2") ;
}


private void xrTableCell107_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
             XRTableCell cell = sender as XRTableCell;

        decimal layingFemMortPre = 0;
        decimal layingMaleMortPre = 0;
        decimal totalMortalityPercentage = 0;
            decimal layStartFemBalance = Convert.ToDecimal(GetCurrentColumnValue("LayStartFemBalance") ?? 0);
        decimal layFemMort = Convert.ToDecimal(GetCurrentColumnValue("LayFemMort") ?? 0);

        // Get values for male calculation
        decimal layStartMaleBalance = Convert.ToDecimal(GetCurrentColumnValue("LayStartMaleBalance") ?? 0);
        decimal layMaleMort = Convert.ToDecimal(GetCurrentColumnValue("LayMaleMort") ?? 0);

        // Calculate {@LayingFemMortPre} - Female mortality percentage
        if (layStartFemBalance != 0)
        {
            layingFemMortPre = (layFemMort * 100) / layStartFemBalance;
        }
        else
        {
            layingFemMortPre = 0;
        }

        // Calculate {@LayingmaleMortPre} - Male mortality percentage
        if (layStartMaleBalance != 0)
        {
            layingMaleMortPre = (layMaleMort * 100) / layStartMaleBalance;
        }
        else
        {
            layingMaleMortPre = 0;
        }

        // Calculate total (sum of both percentages)
        totalMortalityPercentage = layingFemMortPre + layingMaleMortPre;

        cell.Text = totalMortalityPercentage.ToString("N2") ;

}

private void xrTableCell119_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
             XRTableCell cell = sender as XRTableCell;

        decimal totalLayingFemExcluded = 0;
        decimal totalLayingMaleExcluded = 0;
        decimal layingPeriodFemExcludedPer = 0;
        decimal layingPeriodMaleExcludedPer = 0;
        decimal totalExcludedPercentage = 0;
                // Get values for female calculations
        decimal layStartFemBalance = Convert.ToDecimal(GetCurrentColumnValue("LayStartFemBalance") ?? 0);
        decimal layFemMort = Convert.ToDecimal(GetCurrentColumnValue("LayFemMort") ?? 0);
        decimal layFemCulls = Convert.ToDecimal(GetCurrentColumnValue("LayFemCulls") ?? 0);

        // Get values for male calculations
        decimal layStartMaleBalance = Convert.ToDecimal(GetCurrentColumnValue("LayStartMaleBalance") ?? 0);
        decimal layMaleMort = Convert.ToDecimal(GetCurrentColumnValue("LayMaleMort") ?? 0);
        decimal layMaleCulls = Convert.ToDecimal(GetCurrentColumnValue("LayMaleCulls") ?? 0);
        decimal layMaleSpiking = Convert.ToDecimal(GetCurrentColumnValue("LayMaleSpiking") ?? 0);

        // Calculate {@TotalLayingFemExcluded}
        totalLayingFemExcluded = layFemMort + layFemCulls;

        // Calculate {@TotalLayingMaleExcluded}
        totalLayingMaleExcluded = layMaleMort + layMaleCulls + layMaleSpiking;

        // Calculate {@LayingPeriodFemExcludedPer}
        if (layStartFemBalance != 0)
        {
            layingPeriodFemExcludedPer = (totalLayingFemExcluded * 100) / layStartFemBalance;
        }
        else
        {
            layingPeriodFemExcludedPer = 0;
        }

        // Calculate {@LayingPeriodMaleExcludedPer}
        if (layStartMaleBalance != 0)
        {
            layingPeriodMaleExcludedPer = (totalLayingMaleExcluded * 100) / layStartMaleBalance;
        }
        else
        {
            layingPeriodMaleExcludedPer = 0;
        }

        // Calculate total (sum of both percentages)
        totalExcludedPercentage = layingPeriodFemExcludedPer + layingPeriodMaleExcludedPer;
        cell.Text = totalExcludedPercentage.ToString("N2") ;
}

private void xrTableCell29_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

    // Get FemalePOL and TotalEggs values
    decimal femalePOL = Convert.ToDecimal(GetCurrentColumnValue("FemalePOL") ?? 0);
    decimal totalEggs = Convert.ToDecimal(GetCurrentColumnValue("TotalEggs") ?? 0);

    if (femalePOL != 0)
    {
        // Calculate eggs per female at POL
        decimal result = totalEggs / femalePOL;
        cell.Text = result.ToString("N2");
    }
    else
    {
        cell.Text = "0.00";
    }
}

private void xrTableCell35_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

    // Get TotalEggs and HatEggs values
    decimal totalEggs = Convert.ToDecimal(GetCurrentColumnValue("TotalEggs") ?? 0);
    decimal hatEggs = Convert.ToDecimal(GetCurrentColumnValue("HatEggs") ?? 0);

    if (totalEggs != 0)
    {
        // Calculate hatching eggs percentage
        decimal result = (hatEggs * 100) / totalEggs;
        cell.Text = result.ToString("N2");
    }
    else
    {
        cell.Text = "0.00";
    }
}

